// // (1) disable: Disables the counter. Active low.
// (2) reset: Asynchronous reset of the counter. Active low.
// (3) clk: Clock signal.
// (4) up_down: Determines the counting direction. Low for up, high for down.
module top_module(
	input clk,
	input enable,
	input reset,
	input up_down,
	output reg [3:0] q);always @(posedge clk) begin
	if (reset)
		q <= 4'b0000;
	else if (enable)
		q <= up_down ? q + 1 : q - 1;
end
endmodule

